<!DOCTYPE html>
<html lang="pt-BR">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Orçamento de Tattoo 3D - Manequim Premium</title>
<style>
:root{--bg:#050505;--card:#101013;--line:rgba(255,255,255,.14);--text:#fff;--muted:#aaa;--red:#e7332f;--green:#25d366}*{box-sizing:border-box}body{margin:0;background:radial-gradient(circle at 50% 0,rgba(231,51,47,.15),transparent 35%),#050505;color:#fff;font-family:Arial,Helvetica,sans-serif;padding:0 14px 24px}.shell{max-width:1480px;margin:auto}.nav{height:70px;display:flex;align-items:center;justify-content:space-between;border-bottom:1px solid var(--line)}.brand{display:flex;gap:12px;align-items:center;font-weight:900;text-transform:uppercase;letter-spacing:2px}.logo{border:1px solid var(--red);color:var(--red);width:42px;height:42px;display:grid;place-items:center;font-size:24px}.top-zap,.zap,.mobile-cta{background:linear-gradient(#ef3d37,#b81916);border:1px solid rgba(255,255,255,.18);color:#fff;text-decoration:none;border-radius:8px;padding:13px 18px;font-weight:900;text-transform:uppercase}.hero{display:grid;grid-template-columns:minmax(0,1fr)420px;gap:22px;margin-top:22px}.stage,.side-card,.regions,.foot-card{background:linear-gradient(180deg,rgba(18,18,20,.96),rgba(5,5,6,.97));border:1px solid var(--line);border-radius:14px;box-shadow:0 26px 80px rgba(0,0,0,.42)}.stage{padding:22px}h1{margin:0;font-size:clamp(30px,4vw,52px);text-transform:uppercase}.lead{color:#ddd}.version{display:inline-block;margin-left:8px;padding:4px 8px;border:1px solid rgba(231,51,47,.45);border-radius:999px;color:#ff6b63;font-size:12px;vertical-align:middle}.segmented{display:inline-flex;border:1px solid var(--line);border-radius:8px;overflow:hidden;margin:10px 0 18px;background:#080808}.segmented button{border:0;background:transparent;color:#ddd;padding:13px 22px;font-weight:900}.segmented button.active{background:linear-gradient(180deg,var(--red),#75110f);color:#fff}.map-box{position:relative;width:min(100%,560px);height:670px;margin:auto;border-radius:12px;background:#050505;overflow:hidden}.map-box.hidden{display:none}.body-render{position:absolute;left:50%;top:50%;height:96%;max-width:76%;transform:translate(-50%,-50%);object-fit:contain;filter:drop-shadow(0 26px 38px rgba(0,0,0,.9));pointer-events:none;user-select:none}.hotspot{position:absolute;z-index:2;border:1px solid transparent;background:transparent;border-radius:999px;color:transparent;transition:.14s}.hotspot:hover,.hotspot.focused{border-color:rgba(255,110,100,.85);background:rgba(231,51,47,.18);box-shadow:0 0 18px rgba(255,75,69,.65)}.hotspot.selected{border-color:#fff;background:rgba(231,51,47,.46);box-shadow:0 0 28px rgba(255,75,69,.95)}.legend{display:flex;justify-content:center;gap:22px;color:#ddd;margin-top:13px}.dot{display:inline-block;width:13px;height:13px;border-radius:50%;border:1px solid #fff;margin-right:7px}.dot.sel{background:var(--red)}.side{display:grid;gap:16px}.side-card{padding:18px}.side-title{display:flex;justify-content:space-between;align-items:center}.side-title h2{margin:0;text-transform:uppercase}.count{background:var(--red);border-radius:50%;width:30px;height:30px;display:grid;place-items:center;font-weight:900}.selection-list{display:grid;gap:8px;min-height:70px}.pill{display:grid;grid-template-columns:1fr auto;gap:10px;padding:11px 12px;border:1px solid var(--line);border-radius:8px;background:rgba(255,255,255,.04)}.pill small{display:block;color:#bbb;margin-top:4px}.pill button{background:transparent;border:0;color:#ddd;font-size:22px}.price-card{text-align:center}.price-label{color:#bbb;text-transform:uppercase}.price{color:#ff4b45;font-size:clamp(30px,4vw,45px);font-weight:900;margin:12px 0}.desc{color:#ddd;line-height:1.45}.promo-box{margin-top:12px;padding:12px;border:1px solid rgba(37,211,102,.24);border-radius:8px;background:rgba(37,211,102,.06);color:#d8ffe5;text-align:left}.promo-row{display:grid;grid-template-columns:1fr auto;gap:8px;margin-top:12px}.promo-row select,.promo-row button,input,textarea{border:1px solid var(--line);border-radius:8px;background:#080808;color:#fff;padding:12px}.promo-row button{background:rgba(231,51,47,.22);font-weight:900}.field{display:grid;gap:7px;margin-top:12px}.field label{font-size:12px;text-transform:uppercase;font-weight:900;color:#ddd}.field textarea{min-height:90px;resize:vertical}.zap{display:grid;place-items:center;margin-top:16px;min-height:62px}.note{font-size:12px;color:#aaa;text-align:center}.regions{padding:18px;margin-top:22px}.regions-head{display:flex;justify-content:space-between;align-items:end;gap:12px;margin-bottom:14px}.regions-head h2{margin:0;text-transform:uppercase}.regions-head p{margin:0;color:#bbb}.region-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(118px,1fr));gap:10px}.region-card{border:1px solid var(--line);border-radius:10px;background:#090909;color:#fff;min-height:128px;padding:8px;display:grid;grid-template-rows:1fr auto;gap:6px;font-size:10px;font-weight:900;text-transform:uppercase;text-align:center;overflow:hidden}.region-card.selected{border-color:#fff;box-shadow:0 0 18px rgba(231,51,47,.55)}.mini{position:relative;height:82px;border-radius:8px;background:#030303;overflow:hidden}.mini img{position:absolute;left:50%;top:50%;height:120%;max-width:92%;transform:translate(-50%,-50%);object-fit:contain;opacity:.9}.mini-hot{position:absolute;border-radius:999px;background:rgba(231,51,47,.58);border:1px solid rgba(255,255,255,.7);box-shadow:0 0 14px rgba(255,75,69,.8)}.foot{display:grid;grid-template-columns:repeat(4,1fr);gap:12px;margin-top:18px}.foot-card{padding:18px;color:#ddd}.foot-card b{display:block;color:#fff;text-transform:uppercase;margin-bottom:8px}.tooltip{position:fixed;z-index:30;pointer-events:none;opacity:0;transform:translate(12px,12px);padding:8px 10px;border:1px solid var(--line);border-radius:8px;background:#050505;color:#fff;font-weight:900;box-shadow:0 10px 30px #000}.tooltip.show{opacity:1}.mobile-cta{display:none;position:fixed;left:12px;right:12px;bottom:12px;z-index:20;text-align:center}@media(max-width:1180px){.hero{grid-template-columns:1fr}.foot{grid-template-columns:1fr 1fr}}@media(max-width:720px){body{padding:0 10px 84px}.top-zap{display:none}.map-box{height:590px}.region-grid{grid-template-columns:repeat(3,1fr)}.foot{grid-template-columns:1fr}.mobile-cta{display:block}.promo-row{grid-template-columns:1fr}}
</style>
</head>
<body>
<div class="shell">
<nav class="nav"><div class="brand"><span class="logo">DA</span><span>Daniel Araujo<br><small>Tattoo</small></span></div><a class="top-zap" id="topZap" href="#" target="_blank">Chamar no WhatsApp</a></nav>
<section class="hero"><main class="stage"><h1>Orçamento de Tattoo 3D <span class="version">manequim premium v4</span></h1><p class="lead">Selecione as áreas do corpo e receba uma estimativa personalizada.</p><div class="segmented"><button class="active" type="button" data-view="frente">Frente</button><button type="button" data-view="costas">Costas</button></div><div id="frontBox" class="map-box"></div><div id="backBox" class="map-box hidden"></div><div class="legend"><span><i class="dot sel"></i>Selecionado</span><span><i class="dot"></i>Disponível</span></div></main><aside class="side"><section class="side-card"><div class="side-title"><h2>Sua seleção</h2><span id="count" class="count">0</span></div><div id="selectionList" class="selection-list"></div></section><section class="side-card price-card"><div class="price-label">Pré-orçamento</div><div id="preco" class="price">---</div><p id="descricao" class="desc">Clique em uma ou mais regiões para montar a estimativa inicial.</p><div id="promoCurrent" class="promo-box" style="display:none"></div><div class="promo-row"><select id="promoSelect"></select><button id="applyPromo" type="button">Aplicar</button></div></section><section class="side-card"><div class="field"><label>Nome completo</label><input id="cliente" placeholder="Digite seu nome"></div><div class="field"><label>Referência / ideia da tattoo</label><textarea id="referenciaTexto" maxlength="500" placeholder="Descreva sua ideia, estilo, referência..."></textarea></div><a id="zap" class="zap" href="#" target="_blank">Receber orçamento no WhatsApp</a><p class="note">Você será redirecionado com uma mensagem pronta.</p></section></aside></section>
<section class="regions"><div class="regions-head"><h2>Todas as regiões disponíveis</h2><p>Clique em qualquer região para selecionar</p></div><div id="regionGrid" class="region-grid"></div></section>
<section class="foot"><div class="foot-card"><b>Como funciona</b>Selecione áreas, veja a estimativa e envie pelo WhatsApp.</div><div class="foot-card"><b>Orçamento personalizado</b>O valor final depende do tamanho, estilo e detalhamento.</div><div class="foot-card"><b>Atendimento rápido</b>As informações chegam organizadas.</div><div class="foot-card"><b>100% seguro</b>Seus dados não são compartilhados.</div></section>
</div><div id="tooltip" class="tooltip"></div><a id="mobileCta" class="mobile-cta" href="#" target="_blank">Receber orçamento no WhatsApp</a>
<script>
const ASSET_VERSION='v4-20260620-premium';
const FRONT_IMG='https://raw.githubusercontent.com/danielaraujodasilva/tatuagem/main/orcamento/assets/body-front-3d.svg?'+ASSET_VERSION;
const BACK_IMG='https://raw.githubusercontent.com/danielaraujodasilva/tatuagem/main/orcamento/assets/body-back-3d.svg?'+ASSET_VERSION;
function area(titulo,min,max,desc){return{titulo,min,max,desc}}function promo(titulo,desc,ids,desconto,view){return{titulo,desc,ids,desconto,view}}const phone='5511947573311';const areas={cabeca:area('Cabeça',2500,6500,'Área extrema e muito visível.'),pescoco:area('Pescoço',1500,3500,'Região de alto impacto.'),ombros:area('Ombro',1800,4200,'Excelente para encaixe anatômico.'),peito:area('Peitoral',2500,7000,'Área grande e visual.'),abdomen:area('Abdômen',2000,5600,'Área ampla e sensível.'),costela:area('Costela',1800,5600,'Ótima para composições laterais.'),quadril:area('Quadril',1500,4200,'Complemento de perna ou abdômen.'),costas_superior:area('Costas superior',1800,5200,'Área forte para impacto.'),costas_media:area('Costas média',1800,5600,'Boa para peças centrais.'),costas_inferior:area('Costas inferior',1500,4200,'Região boa para complemento.'),lombar:area('Lombar',1500,4200,'Boa para peças centrais.'),braco_interno:area('Braço superior interno',1200,3500,'Metade superior interna.'),braco_externo:area('Braço superior externo',1400,3900,'Metade superior externa.'),antebraco_interno:area('Antebraço interno',1200,3400,'Área muito procurada.'),antebraco_externo:area('Antebraço externo',1200,3200,'Boa leitura no dia a dia.'),pulso:area('Punho',600,1600,'Área menor e delicada.'),mao_palma:area('Mão palma',900,2800,'Área delicada e de alto desgaste.'),mao_dorso:area('Mão dorso',900,2800,'Área muito visível.'),coxa_frontal:area('Coxa frontal',2500,7200,'Área ampla para peças grandes.'),coxa_posterior:area('Coxa posterior',2300,6600,'Boa para fechamento.'),gluteo:area('Glúteos',1800,4600,'Complemento de perna ou quadril.'),joelho:area('Joelho anterior',1200,3800,'Área complexa.'),joelho_posterior:area('Joelho posterior',900,2700,'Área sensível.'),canela:area('Canela',1800,4800,'Área de impacto visual.'),panturrilha:area('Panturrilha',1800,4800,'Boa curvatura.'),tornozelo:area('Tornozelo',600,1900,'Área menor para detalhes.'),pe_dorso:area('Pé dorso',900,2800,'Área visível.'),pe_planta:area('Pé planta',700,2200,'Alto desgaste.')};
const raw={frente:[['cabeca','cabeca','Cabeça',46,5,8,9],['pescoco','pescoco','Pescoço',45,15,10,5],['ombro_esq_frente','ombros','Ombro esq.',30,18,14,8],['ombro_dir_frente','ombros','Ombro dir.',56,18,14,8],['peito_esq','peito','Peitoral esq.',38,24,12,13],['peito_dir','peito','Peitoral dir.',51,24,12,13],['abdomen','abdomen','Abdômen',43,37,14,18],['costela_esq','costela','Costela esq.',35,34,9,20],['costela_dir','costela','Costela dir.',57,34,9,20],['quadril','quadril','Quadril',41,54,18,9],['braco_esq_frente','braco_interno','Braço sup. interno esq.',23,26,11,21],['braco_dir_frente','braco_interno','Braço sup. interno dir.',66,26,11,21],['antebraco_esq_interno','antebraco_interno','Antebraço interno esq.',17,44,10,21],['antebraco_dir_interno','antebraco_interno','Antebraço interno dir.',73,44,10,21],['pulso_esq','pulso','Punho esq.',16,64,8,5],['pulso_dir','pulso','Punho dir.',76,64,8,5],['mao_esq_palma','mao_palma','Mão palma esq.',13,68,11,11],['mao_dir_palma','mao_palma','Mão palma dir.',77,68,11,11],['coxa_esq_frontal','coxa_frontal','Coxa frontal esq.',36,61,12,24],['coxa_dir_frontal','coxa_frontal','Coxa frontal dir.',52,61,12,24],['joelho_esq','joelho','Joelho esq.',38,84,10,7],['joelho_dir','joelho','Joelho dir.',53,84,10,7],['canela_esq','canela','Canela esq.',36,90,10,20],['canela_dir','canela','Canela dir.',54,90,10,20],['tornozelo_esq','tornozelo','Tornozelo esq.',35,109,11,5],['tornozelo_dir','tornozelo','Tornozelo dir.',55,109,11,5],['pe_esq_dorso','pe_dorso','Pé dorso esq.',33,113,14,7],['pe_dir_dorso','pe_dorso','Pé dorso dir.',54,113,14,7]],costas:[['cabeca_costas','cabeca','Cabeça',46,5,8,9],['nuca','pescoco','Nuca / pescoço',45,15,10,5],['ombro_esq_costas','ombros','Ombro esq.',30,18,14,8],['ombro_dir_costas','ombros','Ombro dir.',56,18,14,8],['costas_esq_alta','costas_superior','Costas superior esq.',37,23,13,16],['costas_dir_alta','costas_superior','Costas superior dir.',50,23,13,16],['costas_esq_media','costas_media','Costas média esq.',38,38,12,13],['costas_dir_media','costas_media','Costas média dir.',50,38,12,13],['costas_esq_baixa','costas_inferior','Costas inferior esq.',39,50,11,11],['costas_dir_baixa','costas_inferior','Costas inferior dir.',50,50,11,11],['lombar','lombar','Lombar',41,57,18,8],['braco_esq_costas','braco_externo','Braço sup. externo esq.',23,26,11,21],['braco_dir_costas','braco_externo','Braço sup. externo dir.',66,26,11,21],['antebraco_esq_externo','antebraco_externo','Antebraço externo esq.',17,44,10,21],['antebraco_dir_externo','antebraco_externo','Antebraço externo dir.',73,44,10,21],['mao_esq_dorso','mao_dorso','Mão dorso esq.',13,68,11,11],['mao_dir_dorso','mao_dorso','Mão dorso dir.',77,68,11,11],['gluteo_esq','gluteo','Glúteo esq.',38,62,12,12],['gluteo_dir','gluteo','Glúteo dir.',51,62,12,12],['coxa_esq_posterior','coxa_posterior','Coxa posterior esq.',36,72,12,22],['coxa_dir_posterior','coxa_posterior','Coxa posterior dir.',52,72,12,22],['joelho_esq_posterior','joelho_posterior','Joelho posterior esq.',38,93,10,6],['joelho_dir_posterior','joelho_posterior','Joelho posterior dir.',53,93,10,6],['panturrilha_esq','panturrilha','Panturrilha esq.',36,99,10,17],['panturrilha_dir','panturrilha','Panturrilha dir.',54,99,10,17],['tornozelo_esq_costas','tornozelo','Tornozelo esq.',35,115,11,5],['tornozelo_dir_costas','tornozelo','Tornozelo dir.',55,115,11,5],['pe_esq_planta','pe_planta','Pé planta esq.',33,119,14,7],['pe_dir_planta','pe_planta','Pé planta dir.',54,119,14,7]]};
function norm(h){let y=4+h[4]*.74,ht=h[6]*.74;return{left:h[3]+'%',top:y+'%',width:h[5]+'%',height:ht+'%'}}const promos=[promo('Braço externo esquerdo','Ombro + braço superior externo + antebraço externo',['ombro_esq_costas','braco_esq_costas','antebraco_esq_externo'],.88,'costas'),promo('Braço interno esquerdo','Braço superior interno + antebraço interno',['braco_esq_frente','antebraco_esq_interno'],.9,'frente'),promo('Peitoral completo','Peito esquerdo + direito',['peito_esq','peito_dir'],.9,'frente'),promo('Costas completa','Costas superior + média + inferior + lombar',['costas_esq_alta','costas_dir_alta','costas_esq_media','costas_dir_media','costas_esq_baixa','costas_dir_baixa','lombar'],.82,'costas')];const $=id=>document.getElementById(id),selected=new Map();function money(v){return Number(v||0).toLocaleString('pt-BR',{style:'currency',currency:'BRL',maximumFractionDigits:0})}function esc(v=''){return String(v).replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#039;'}[c]))}function draw(view,box,img){const b=$(box);b.innerHTML=`<img class="body-render" src="${img}" alt="Boneco ${view}">`;raw[view].forEach(h=>{const e=document.createElement('button');e.className='hotspot';e.type='button';e.dataset.id=h[0];e.dataset.region=h[1];e.dataset.label=h[2];Object.assign(e.style,norm(h));e.onclick=()=>selectPart(e);e.onmousemove=ev=>tip(ev,h[2]);e.onmouseleave=()=>$('tooltip').classList.remove('show');b.appendChild(e)})}function tip(e,t){$('tooltip').textContent=t;$('tooltip').style.left=e.clientX+'px';$('tooltip').style.top=e.clientY+'px';$('tooltip').classList.add('show')}function selectPart(e){const item={id:e.dataset.id,region:e.dataset.region,label:e.dataset.label};selected.has(item.id)?selected.delete(item.id):selected.set(item.id,item);update()}function selectRegion(region){const els=[...document.querySelectorAll(`.hotspot[data-region="${region}"]`)];const all=els.length&&els.every(e=>selected.has(e.dataset.id));els.forEach(e=>{const item={id:e.dataset.id,region:e.dataset.region,label:e.dataset.label};all?selected.delete(item.id):selected.set(item.id,item)});update()}function calc(){if(!selected.size)return null;const t=[...selected.values()].reduce((a,i)=>{const d=areas[i.region];return{min:a.min+(d?.min||0),max:a.max+(d?.max||0)}},{min:0,max:0});const p=promos.filter(p=>p.ids.every(id=>selected.has(id))).sort((a,b)=>a.desconto-b.desconto)[0];const disc=p?.desconto||1;return{min:Math.round(t.min*disc/50)*50,max:Math.round(t.max*disc/50)*50,promo:p,off:p?Math.round((1-disc)*100):0}}function update(){document.querySelectorAll('.hotspot').forEach(e=>e.classList.toggle('selected',selected.has(e.dataset.id)));document.querySelectorAll('.region-card').forEach(c=>c.classList.toggle('selected',[...selected.values()].some(i=>i.region===c.dataset.region)));const items=[...selected.values()],est=calc();$('count').innerText=items.length;$('selectionList').innerHTML=items.length?items.map(i=>{const d=areas[i.region];return`<div class="pill"><span>${esc(i.label)}<small>${money(d.min)} - ${money(d.max)}</small></span><button data-remove="${i.id}">×</button></div>`}).join(''):'<div style="color:#aaa">Nenhuma região selecionada ainda.</div>';$('preco').innerText=est?`${money(est.min)} - ${money(est.max)}`:'---';$('descricao').innerText=est?(est.promo?`${est.promo.titulo}: ${est.promo.desc}`:areas[items.at(-1).region].desc):'Clique em uma ou mais regiões para montar a estimativa inicial.';$('promoCurrent').style.display=est?.promo?'block':'none';if(est?.promo)$('promoCurrent').innerHTML=`<b>Promoção aplicada!</b> ${est.off}% OFF`;renderPromos();links()}function renderPromos(){$('promoSelect').innerHTML='<option value="">Selecionar promoção</option>'+promos.map((p,i)=>`<option value="${i}">${p.titulo}</option>`).join('')}function links(){const est=calc();const client=$('cliente').value.trim()||'Cliente ainda não informou';const idea=$('referenciaTexto').value.trim()||'Não descreveu ainda';const areaText=[...selected.values()].map(i=>i.label).join(', ')||'a definir';const price=est?`${money(est.min)} a ${money(est.max)}`:'Aguardando seleção';const msg=['Olá! Quero um orçamento de tatuagem.',`Nome: ${client}`,`Área escolhida: ${areaText}`,`Referência/ideia: ${idea}`,`Pré-orçamento: ${price}`,'Sei que o valor final depende de avaliação.'].join('\n');const href=`https://wa.me/${phone}?text=${encodeURIComponent(msg)}&utm_source=orcamento_3d`;['zap','mobileCta','topZap'].forEach(id=>$(id).href=href)}function renderGrid(){const first={};['frente','costas'].forEach(v=>raw[v].forEach(h=>{if(!first[h[1]])first[h[1]]={h,v}}));$('regionGrid').innerHTML=Object.keys(areas).map(k=>{const f=first[k];const img=f?.v==='costas'?BACK_IMG:FRONT_IMG;const st=f?norm(f.h):{left:'45%',top:'45%',width:'12%',height:'12%'};return`<button class="region-card" data-region="${k}"><span class="mini"><img src="${img}"><i class="mini-hot" style="left:${st.left};top:${st.top};width:${st.width};height:${st.height}"></i></span><span>${esc(areas[k].titulo)}</span></button>`}).join('');document.querySelectorAll('.region-card').forEach(b=>b.onclick=()=>selectRegion(b.dataset.region))}function setView(v){document.querySelectorAll('[data-view]').forEach(b=>b.classList.toggle('active',b.dataset.view===v));$('frontBox').classList.toggle('hidden',v!=='frente');$('backBox').classList.toggle('hidden',v!=='costas')}$('selectionList').onclick=e=>{const b=e.target.closest('[data-remove]');if(b){selected.delete(b.dataset.remove);update()}};$('applyPromo').onclick=()=>{const p=promos[Number($('promoSelect').value)];if(!p)return;selected.clear();setView(p.view);p.ids.forEach(id=>{const e=document.querySelector(`[data-id="${id}"]`);if(e)selected.set(id,{id,region:e.dataset.region,label:e.dataset.label})});update()};document.querySelectorAll('[data-view]').forEach(b=>b.onclick=()=>setView(b.dataset.view));['cliente','referenciaTexto'].forEach(id=>$(id).oninput=links);draw('frente','frontBox',FRONT_IMG);draw('costas','backBox',BACK_IMG);renderGrid();renderPromos();update();
</script>
</body>
</html>